export interface Platform {
    name: string;
    detect(url: string): boolean;
    preprocess(html: string, url: string): string;
    postprocess?(markdown: string): string;
    /** Platform-specific meta tag selectors for title/author/time extraction */
    metaSelectors?: MetaSelectors;
    /** Convert URL to mobile version (for platforms with anti-scraping on desktop) */
    getMobileUrl?(url: string): string;
}
export interface MetaSelectors {
    title?: string;
    author?: string;
    time?: string;
}
export type FetchStrategy = 'curl' | 'wget' | 'playwright' | 'auto';
export interface ConvertOptions {
    url: string;
    html?: string;
    platform?: string;
    selector?: string;
    noiseSelectors?: string[];
    includeMetadata?: boolean;
    fetchStrategy?: FetchStrategy;
    customPlatform?: Platform;
    timeout?: number;
    verbose?: boolean;
    downloadImages?: boolean;
    outputDir?: string;
}
export interface NewsMetadata {
    title?: string;
    author?: string;
    publishTime?: string;
    platform: string;
    imageCount: number;
    contentLength: number;
    localCoverPath?: string;
    downloadedImages?: number;
    fetchMethod?: string;
    coverImage?: string | null;
}
export interface ConvertResult {
    markdown: string;
    metadata: NewsMetadata;
    html?: string;
}
export interface FetchResult {
    html: string;
    method: string;
    success: boolean;
    error?: string;
}
